defs.script:
    document.addEventListener("DOMContentLoaded", function() {
  const hoje = new Date();
  const dataAlvo = new Date(hoje.valueOf());
  const numeroDia = (hoje.getDay() + 6) % 7;
  dataAlvo.setDate(dataAlvo.getDate() - numeroDia + 3);
  const primeiroQuinta = dataAlvo.valueOf();
  dataAlvo.setMonth(0, 1);
  if (dataAlvo.getDay() !== 4) {
    dataAlvo.setMonth(0, 1 + ((4 - dataAlvo.getDay() + 7) % 7));
  }
  const numeroSemana = 1 + Math.ceil((primeiroQuinta - dataAlvo) / 604800000);
  const anoDuasLetras = hoje.getFullYear().toString().slice(-2);
  const semanaFormatada = numeroSemana.toString().padStart(2, '0');

  const tspan = document.getElementById("tspan21");
  if (tspan) {
    tspan.textContent = "RP2-80   " + semanaFormatada + "/" + anoDuasLetras;
  }
});
